<?php
declare(strict_types=1);require dirname(__DIR__).'/app/bootstrap.php';$result=null;$searched=false;if($_SERVER['REQUEST_METHOD']==='POST'){$searched=true;$code=normalize_code((string)($_POST['code']??''));$s=$db->prepare('SELECT * FROM licenses WHERE code=?');$s->execute([$code]);$result=$s->fetch();}function h(?string $v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
?><!doctype html><html lang="ar" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>فحص كود GPS Plus</title><link rel="stylesheet" href="assets/style.css"></head><body><main class="page"><section class="card check-card"><div class="logo">GPS</div><h1 class="center">فحص كود GPS Plus</h1><p class="muted">اعرف مدة الكود وحالة الاستخدام وتاريخ التفعيل والانتهاء</p><form method="post" class="stack"><input name="code" value="<?=h($_POST['code']??'')?>" placeholder="GPS-XXXXXXXXXXXXXXXX" required><button>فحص الكود</button></form><?php if($searched):?><div class="result <?=$result?'success':'error'?>"><?php if($result):?><?php $expired=$result['expires_at']&&strtotime($result['expires_at'])<time();?><h2>تفاصيل الكود</h2><div class="details public"><div><span>المدة</span><b><?=intval($result['duration_days'])?> يوم</b></div><div><span>الحالة</span><b><span class="badge <?=$expired?'bad':($result['activated_at']?'ok':'warn')?>"><?=$expired?'منتهي':($result['activated_at']?'مستخدم':'غير مستخدم')?></span></b></div><div><span>تاريخ الاستخدام</span><b><?=h($result['activated_at']?:'لم يُستخدم بعد')?></b></div><div><span>تاريخ الانتهاء</span><b><?=h($result['expires_at']?:'يبدأ عند أول استخدام')?></b></div></div><?php else:?><h2>الكود غير موجود</h2><p>تحقق من كتابة الكود بشكل صحيح.</p><?php endif;?></div><?php endif;?></section></main></body></html>
